// ============================================================
// CONFIGURATION — Add your Google Alert RSS URLs here.
//
// HOW TO CREATE A GOOGLE ALERT RSS FEED:
// 1. Go to https://www.google.com/alerts
// 2. Search for: site:linkedin.com/posts "Person Name"
//    e.g.  site:linkedin.com/posts "Jean-Marie Bruce"
// 3. Click 'Show options' → Deliver to: RSS Feed
// 4. Click 'Create Alert' → copy the RSS URL shown.
// 5. Paste it below.
// ============================================================

return [
  {
    json: {
      person: "Jean-Marie Bruce",
      rss_url: "https://www.google.com/alerts/feeds/YOUR_FEED_ID_1/YOUR_FEED_TOKEN_1"
    }
  },
  {
    json: {
      person: "Bill Gates",
      rss_url: "https://www.google.com/alerts/feeds/YOUR_FEED_ID_2/YOUR_FEED_TOKEN_2"
    }
  }
  // Add more people here following the same pattern
];

// ============================================================
// PARSE RSS XML → individual post items
//
// Google Alerts returns Atom 1.0 XML. We parse entries
// manually using regex — reliable for this feed format.
// ============================================================

const xml = $input.item.json.data || "";
const person = $('Loop Over People').item.json.person || "";
const rss_url = $('Loop Over People').item.json.rss_url || "";

if (!xml || xml.length < 50) {
  return [{ json: { skip: true, reason: "Empty RSS response", rss_url } }];
}

// Extract <entry> blocks (Atom) or <item> blocks (RSS 2.0)
const entryRegex = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
const itemRegex  = /<item[^>]*>([\s\S]*?)<\/item>/gi;

const blocks = [];
let m;
while ((m = entryRegex.exec(xml)) !== null) blocks.push(m[1]);
if (blocks.length === 0) {
  while ((m = itemRegex.exec(xml)) !== null) blocks.push(m[1]);
}

if (blocks.length === 0) {
  return [{ json: { skip: true, reason: "No entries found in RSS", rss_url } }];
}

function tag(block, name) {
  const cdata = block.match(new RegExp('<' + name + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/' + name + '>', 'i'));
  if (cdata) return cdata[1].trim();
  const plain = block.match(new RegExp('<' + name + '[^>]*>([\\s\\S]*?)<\/' + name + '>', 'i'));
  return plain ? plain[1].trim() : '';
}

function extractLink(block) {
  // Atom: <link href="..."/>
  const href = block.match(/<link[^>]+href=["']([^"']+)["']/i);
  if (href) return href[1];
  // RSS 2.0: <link>url</link>
  const text = block.match(/<link[^>]*>([^<]+)<\/link>/i);
  return text ? text[1].trim() : '';
}

const results = [];
for (const block of blocks) {
  let link = extractLink(block);
  // Google Alerts wraps the real URL: …&url=https%3A…
  const urlParam = link.match(/[?&]url=([^&]+)/);
  if (urlParam) link = decodeURIComponent(urlParam[1]);

  const title   = tag(block, 'title');
  const content = tag(block, 'content') || tag(block, 'summary') || tag(block, 'description');
  const guid    = tag(block, 'id') || tag(block, 'guid') || link;
  const pubDate = tag(block, 'published') || tag(block, 'updated') || tag(block, 'pubDate');

  results.push({ json: { link, title, content, guid, pubDate, person } });
}

return results;

// Deduplication — skip posts already processed.
// Uses n8n workflow static data (built-in, no external DB).

const seen = $getWorkflowStaticData('node');
if (!seen.processed_guids) seen.processed_guids = [];

const MAX_HISTORY = 500;
const newItems = [];

for (const item of $input.all()) {
  const guid = item.json.guid || item.json.link || item.json.title;
  if (!guid) continue;
  if (seen.processed_guids.includes(guid)) continue;
  newItems.push(item);
  seen.processed_guids.push(guid);
}

if (seen.processed_guids.length > MAX_HISTORY) {
  seen.processed_guids = seen.processed_guids.slice(-MAX_HISTORY);
}

if (newItems.length === 0) {
  return [{ json: { skip: true, reason: 'No new posts found' } }];
}

return newItems;

const item = $input.item.json;

// Author: prefer config person name, fall back to extracting from URL slug
let author = item.person || '';
if (!author) {
  const m = (item.link || '').match(/linkedin\.com\/posts\/([^_?/]+)/);
  if (m) author = m[1].replace(/-/g, ' ');
}
author = author || 'Author';

// Strip HTML from content snippet
const rawText = item.content || item.title || '';
const post_text = rawText.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

return {
  json: {
    post_url:  item.link || '',
    post_text: post_text,
    author:    author,
    pub_date:  item.pubDate || '',
    guid:      item.guid || item.link || item.title
  }
};

// Extract LinkedIn post URN from the URL
// e.g. ugcPost-7212480850238582785 → urn:li:ugcPost:7212480850238582785

const postUrl   = $('Parse RSS Item').item.json.post_url || '';
const aiComment = $input.item.json.output || '';

let urn = '';

const ugc  = postUrl.match(/ugcPost-([0-9]+)/);
const shr  = postUrl.match(/share-([0-9]+)/);
const act  = postUrl.match(/activity-([0-9]+)/);

if (ugc)      urn = 'urn:li:ugcPost:'  + ugc[1];
else if (shr) urn = 'urn:li:share:'   + shr[1];
else if (act) urn = 'urn:li:activity:' + act[1];

if (!urn) {
  return { json: { skip: true, reason: 'No URN in URL: ' + postUrl, post_url: postUrl } };
}

return { json: { urn, comment: aiComment, post_url: postUrl } };
